    { p: "¿Cuál es una propuesta de valor de AWS Cloud?", ops: ["AWS es responsable de la seguridad en AWS Cloud", "No se requiere contrato a largo plazo", "Aprovisionar nuevos servidores en días", "AWS gestiona las aplicaciones de usuario en AWS Cloud"], r: [1] },
    { p: "¿Qué característica tiene la replicación entre regiones de Amazon S3?", ops: ["Tanto los buckets de origen como los de destino deben tener el versionado deshabilitado", "Los buckets de origen y destino no pueden estar en diferentes regiones de AWS", "Los buckets de S3 configurados para la replicación entre regiones pueden ser propiedad de una o diferentes cuentas de AWS", "El propietario del bucket de origen debe tener las regiones de origen y destino deshabilitadas"], r: [2] },
    { p: "¿De qué es responsable un usuario al ejecutar una aplicación en AWS Cloud?", ops: ["Gestión del hardware físico", "Actualización del hipervisor subyacente", "Proporcionar una lista de usuarios aprobados para el acceso al centro de datos", "Gestión de las actualizaciones de software de la aplicación"], r: [3] },
    { p: "Una empresa necesita ofrecer nueva funcionalidad rápidamente de manera iterativa, minimizando el tiempo de comercialización. ¿Qué característica de AWS Cloud puede proporcionarlo?", ops: ["Elasticidad", "Alta disponibilidad", "Agilidad", "Confiabilidad"], r: [2] },
    { p: "¿Qué características o servicios se pueden usar para monitorizar costos y gastos de una cuenta de AWS? (Elige dos.)", ops: ["AWS Cost and Usage Report", "Páginas de productos de AWS", "Calculadora Mensual Simple de AWS", "Alertas de facturación y alarmas de Amazon CloudWatch", "API de lista de precios de AWS"], r: [0,3], multi: true },
    { p: "Amazon Route 53 permite a los usuarios:", ops: ["Cifrar datos en tránsito", "Registrar nombres de dominio DNS", "Generar y gestionar certificados SSL", "Establecer una conexión de red dedicada a AWS"], r: [1] }
